import React from 'react';
import './Hero.css';

function Hero() {
  return (
    <section className="hero">
      <div className="hero-text">
        <p>Limited Time Offer 30% Off</p>
        <h1>Experience Pure Sound - Your Perfect Headphones Awaits!</h1>
        <div>
          <button className="buy-btn">Buy now</button>
          <button className="find-btn">Find more →</button>
        </div>
      </div>
      <div className="hero-image">
        <img src="https://via.placeholder.com/300" alt="Headphones" />
      </div>
    </section>
  );
}

export default Hero;
